class Solution:
    def minIncrements(self, n, cost):
        best = [0] * (n + 1)
        for i in range(1, n + 1):
            best[i] = cost[i - 1]
        total = 0
        for i in range(n // 2, 0, -1):
            left = 2 * i
            right = 2 * i + 1
            total += abs(best[left] - best[right])
            best[i] = cost[i - 1] + max(best[left], best[right])
        return total

