var minIncrements = function(n, cost) {
    const best = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) best[i] = cost[i - 1];
    let total = 0;
    for (let i = Math.floor(n / 2); i >= 1; i--) {
        const left = 2 * i;
        const right = 2 * i + 1;
        total += Math.abs(best[left] - best[right]);
        best[i] = cost[i - 1] + Math.max(best[left], best[right]);
    }
    return total;
};
